import React from "react";
function News(props) {
    console.log(props);

    return (
        <div className="news">
            <div className="news-img">
                <img src={props.article.urlToImage} />
            </div>

            <h1>{props.article.title}</h1>

            <p>{props.article.description}</p>

            <a href="#">Read More</a>

            <div className="source">
                <p>Author : Kusuma</p>
                <p>vijaywani</p>
            </div>
        </div>
    )
}
export default News;
